const STAGES = [1, 3, 7, 14, 30]; // 艾宾浩斯复习间隔（天）
const DAILY_NEW = 36;
const DAY_MS = 24 * 60 * 60 * 1000;

function todayKey() {
  return new Date().toDateString();
}

function addDays(ts, days) {
  return ts + days * DAY_MS;
}

async function callClaude(prompt) {
  const res = await fetch("https://api.anthropic.com/v1/messages", {
    method: "POST",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify({
      model: "claude-sonnet-4-6",
      max_tokens: 600,
      messages: [{ role: "user", content: prompt }],
    }),
  });
  const data = await res.json();
  const block = data.content?.find((c) => c.type === "text");
  return block ? block.text : "";
}

async function generateExample(word, meaning) {
  // 暂不接通真实API（Key不可放在前端代码中），先用占位文本，
  // 部署到Vercel后通过后端环境变量接通真实生成
  await new Promise((r) => setTimeout(r, 200));
  return {
    sentence: `（部署后将显示包含 **${word}** 的AI生成例句）`,
    translation: `（部署后将显示对应中文翻译，释义参考：${meaning}）`,
    placeholder: true,
  };
}

function renderBold(text) {
  const parts = String(text || "").split(/(\*\*[^*]+\*\*)/g);
  return parts.map((part, i) => {
    if (part.startsWith("**") && part.endsWith("**")) {
      return (
        <strong key={i} className="text-indigo-600 font-bold">
          {part.slice(2, -2)}
        </strong>
      );
    }
    return <React.Fragment key={i}>{part}</React.Fragment>;
  });
}

function shuffle(arr) {
  const a = [...arr];
  for (let i = a.length - 1; i > 0; i--) {
    const j = Math.floor(Math.random() * (i + 1));
    [a[i], a[j]] = [a[j], a[i]];
  }
  return a;
}

// 测验场景下隐藏汉字词括号标注（如"진동(振動)" -> "진동"），避免汉字直接泄露中文答案
function quizWord(word) {
  return word.replace(/\([^)]*\)/g, "").trim();
}

const STAGE_PLAN = [
  { name: "第1阶段：词汇积累", range: "6/19 – 7/31", desc: "每日36新词 + 艾宾浩斯复习" },
  { name: "第2阶段：阅读突破", range: "8/1 – 8/31", desc: "每日8新词 + 真题阅读" },
  { name: "第3阶段：综合实战", range: "9/1 – 9/30", desc: "每周1-2套模拟题" },
  { name: "第4阶段：冲刺查漏", range: "10/1 – 10/17", desc: "错题复习 + 写作模板" },
];

export default function App() {
  // progress: { [id]: { status: 'new'|'learning'|'mastered', stage, nextReview, guessRecent } }
  const [progress, setProgress] = useState(() => {
    try {
      const saved = localStorage.getItem("topik_progress");
      return saved ? JSON.parse(saved) : {};
    } catch (e) {
      return {};
    }
  });

  // progress变化时自动写入localStorage
  useEffect(() => {
    try {
      localStorage.setItem("topik_progress", JSON.stringify(progress));
    } catch (e) {
      // 存储失败（如超出容量）时静默忽略，不影响使用
    }
  }, [progress]);

  const [tab, setTab] = useState("learn");
  const [exampleCache, setExampleCache] = useState({});
  const [loadingExample, setLoadingExample] = useState(false);

  const now = Date.now();

  // ---------- 今日学习额度（独立计数器，不依赖单词记录里的字段，避免历史数据干扰）----------
  const [dailyCount, setDailyCount] = useState(() => {
    try {
      const saved = localStorage.getItem("topik_daily_count");
      if (saved) return JSON.parse(saved);
    } catch (e) {}
    return { date: todayKey(), used: 0 };
  });

  useEffect(() => {
    try {
      localStorage.setItem("topik_daily_count", JSON.stringify(dailyCount));
    } catch (e) {}
  }, [dailyCount]);

  // ---------- 学习队列 ----------
  // "今日新词"按自然日封顶DAILY_NEW个，用dailyCount独立计数，不受历史progress记录影响
  const newWords = useMemo(() => {
    const used = dailyCount.date === todayKey() ? dailyCount.used : 0;
    const remainingSlots = Math.max(0, DAILY_NEW - used);
    const untouched = VOCAB.filter((v) => !progress[v.id]);
    return untouched.slice(0, remainingSlots);
  }, [progress, dailyCount]);

  const [learnIndex, setLearnIndex] = useState(0);
  const currentLearnWord = newWords[learnIndex];

  // ---------- 复习队列（用于测验）----------
  const dueWords = useMemo(() => {
    return VOCAB.filter((v) => {
      const p = progress[v.id];
      if (!p || p.status !== "learning") return false;
      return p.nextReview <= now;
    });
  }, [progress, now]);

  const [quizQueue, setQuizQueue] = useState(null);
  const [quizIndex, setQuizIndex] = useState(0);
  const [quizMode, setQuizMode] = useState(null); // 'recognition' | 'production'
  const [quizOptions, setQuizOptions] = useState([]);
  const [quizInput, setQuizInput] = useState("");
  const [quizGuessed, setQuizGuessed] = useState(false);
  const [quizAnswered, setQuizAnswered] = useState(false);
  const [quizCorrect, setQuizCorrect] = useState(false);
  const [quizStats, setQuizStats] = useState({ real: 0, guessed: 0, wrong: 0 });

  const startQuiz = useCallback(() => {
    const queue = shuffle(dueWords);
    setQuizQueue(queue);
    setQuizIndex(0);
    setQuizStats({ real: 0, guessed: 0, wrong: 0 });
    setupQuizItem(queue, 0);
  }, [dueWords]);

  function setupQuizItem(queue, idx) {
    if (!queue || idx >= queue.length) {
      setQuizMode(null);
      return;
    }
    const item = queue[idx];
    const mode = Math.random() < 0.5 ? "recognition" : "production";
    setQuizMode(mode);
    setQuizInput("");
    setQuizGuessed(false);
    setQuizAnswered(false);
    setQuizCorrect(false);
    if (mode === "recognition") {
      const distractors = shuffle(
        VOCAB.filter((v) => v.id !== item.id).map((v) => v.meaning)
      ).slice(0, 3);
      setQuizOptions(shuffle([item.meaning, ...distractors]));
    } else {
      setQuizOptions([]);
    }
  }

  function markLearn(word, action) {
    const today = todayKey();
    setDailyCount((prev) => {
      const used = prev.date === today ? prev.used : 0;
      return { date: today, used: used + 1 };
    });
    setProgress((prev) => {
      const next = { ...prev };
      if (action === "master") {
        next[word.id] = { status: "mastered", stage: -1, nextReview: null, guessRecent: false, learnedDate: today };
      } else {
        // 见过 / 没见过 都进入复习队列，当天即可测验（艾宾浩斯1/3/7/14/30天从第一次测验答对后开始计）
        next[word.id] = {
          status: "learning",
          stage: -1,
          nextReview: now,
          guessRecent: false,
          learnedDate: today,
        };
      }
      return next;
    });
    setLearnIndex((i) => i + 1);
  }

  function recordQuizAnswer(item, correct) {
    setProgress((prev) => {
      const next = { ...prev };
      const p = next[item.id] || { status: "learning", stage: 0 };
      if (quizGuessed && correct) {
        // 猜对：保持当前阶段，但2天后再次复习
        next[item.id] = { ...p, nextReview: addDays(now, 2), guessRecent: true };
      } else if (correct) {
        const newStage = p.stage + 1;
        if (newStage >= STAGES.length) {
          next[item.id] = { ...p, status: "mastered", stage: -1, nextReview: null, guessRecent: false };
        } else {
          next[item.id] = { ...p, stage: newStage, nextReview: addDays(now, STAGES[newStage]), guessRecent: false };
        }
      } else {
        next[item.id] = { ...p, stage: 0, nextReview: addDays(now, STAGES[0]), guessRecent: false };
      }
      return next;
    });
    setQuizStats((s) => ({
      real: s.real + (correct && !quizGuessed ? 1 : 0),
      guessed: s.guessed + (correct && quizGuessed ? 1 : 0),
      wrong: s.wrong + (correct ? 0 : 1),
    }));
  }

  function submitQuizAnswer(selected) {
    if (quizAnswered) return;
    const item = quizQueue[quizIndex];
    let correct;
    if (quizMode === "recognition") {
      correct = selected === item.meaning;
    } else {
      correct = quizInput.trim() === quizWord(item.word);
    }
    setQuizCorrect(correct);
    setQuizAnswered(true);
    recordQuizAnswer(item, correct);
  }

  function nextQuizItem() {
    const ni = quizIndex + 1;
    setQuizIndex(ni);
    setupQuizItem(quizQueue, ni);
  }

  async function loadExample(word) {
    if (exampleCache[word.id] || loadingExample) return;
    setLoadingExample(true);
    const result = await generateExample(word.word, word.meaning);
    setExampleCache((prev) => ({ ...prev, [word.id]: result }));
    setLoadingExample(false);
  }

  // ---------- 进度统计 ----------
  const stats = useMemo(() => {
    let learning = 0, mastered = 0, total = Object.keys(progress).length;
    Object.values(progress).forEach((p) => {
      if (p.status === "mastered") mastered++;
      else if (p.status === "learning") learning++;
    });
    return { total, learning, mastered, untouched: VOCAB.length - total };
  }, [progress]);

  // ---------- 导出/导入（Artifact沙盒禁止文件下载，改为文本框复制/粘贴）----------
  const [exportText, setExportText] = useState(null);
  const [importText, setImportText] = useState("");
  const [importMsg, setImportMsg] = useState("");

  function showExport() {
    setExportText(JSON.stringify(progress));
  }

  function applyImport() {
    try {
      const data = JSON.parse(importText.trim());
      setProgress(data);
      setImportMsg("导入成功");
    } catch (err) {
      setImportMsg("格式错误，导入失败，请确认粘贴内容完整");
    }
  }

  function resetAll() {
    if (!window.confirm("确定要清空所有学习进度吗？此操作不可恢复。")) return;
    setProgress({});
    setDailyCount({ date: todayKey(), used: 0 });
    setLearnIndex(0);
    setImportMsg("已重置全部进度");
  }

  // ================= 渲染 =================
  return (
    <div className="min-h-screen bg-slate-50 text-slate-800 p-4 font-sans">
      <div className="max-w-2xl mx-auto">
        <h1 className="text-xl font-bold mb-1 text-slate-900">TOPIK Ⅱ 词汇备考工具</h1>
        <p className="text-xs text-slate-400 mb-4">
          词库共 {VOCAB.length} 条 · 学习进度已自动保存在本设备浏览器中
        </p>

        {/* Tabs */}
        <div className="flex gap-2 mb-4">
          {[
            ["learn", "学习"],
            ["quiz", "测验"],
            ["progress", "进度"],
          ].map(([key, label]) => (
            <button
              key={key}
              onClick={() => setTab(key)}
              className={`px-4 py-2 rounded-lg text-sm font-medium transition ${
                tab === key
                  ? "bg-indigo-600 text-white"
                  : "bg-white text-slate-500 border border-slate-200"
              }`}
            >
              {label}
            </button>
          ))}
        </div>

        {/* ============ 学习标签 ============ */}
        {tab === "learn" && (
          <div className="bg-white rounded-xl border border-slate-200 p-5">
            {newWords.length === 0 ? (
              <p className="text-slate-500 text-sm">词库已全部学习完毕！🎉</p>
            ) : currentLearnWord ? (
              <div>
                <p className="text-xs text-slate-400 mb-2">
                  今日新词 {learnIndex + 1} / {newWords.length}
                </p>
                <div className="text-2xl font-bold text-slate-900 mb-1 flex items-center gap-2">
                  {currentLearnWord.word}
                  {currentLearnWord.pos && (
                    <span className="text-xs font-medium text-indigo-600 bg-indigo-50 border border-indigo-200 rounded px-1.5 py-0.5">
                      {currentLearnWord.pos}
                    </span>
                  )}
                </div>
                <div className="text-base text-slate-600 mb-4">
                  {currentLearnWord.meaning}
                </div>

                <div className="bg-slate-50 border border-slate-100 rounded-lg p-3 mb-4 min-h-[70px]">
                  {exampleCache[currentLearnWord.id] ? (
                    <div>
                      <p className="text-sm leading-relaxed mb-1">
                        {renderBold(exampleCache[currentLearnWord.id].sentence)}
                      </p>
                      <p className="text-xs text-slate-400">
                        {exampleCache[currentLearnWord.id].translation}
                      </p>
                    </div>
                  ) : (
                    <button
                      onClick={() => loadExample(currentLearnWord)}
                      disabled={loadingExample}
                      className="text-sm text-indigo-600 underline disabled:opacity-50"
                    >
                      {loadingExample ? "AI正在生成例句…" : "生成例句"}
                    </button>
                  )}
                </div>

                <div className="flex gap-2">
                  <button
                    onClick={() => markLearn(currentLearnWord, "seen")}
                    className="flex-1 py-2 rounded-lg bg-slate-100 hover:bg-slate-200 text-sm font-medium"
                  >
                    见过
                  </button>
                  <button
                    onClick={() => markLearn(currentLearnWord, "unseen")}
                    className="flex-1 py-2 rounded-lg bg-slate-100 hover:bg-slate-200 text-sm font-medium"
                  >
                    没见过
                  </button>
                  <button
                    onClick={() => markLearn(currentLearnWord, "master")}
                    className="flex-1 py-2 rounded-lg bg-emerald-100 hover:bg-emerald-200 text-emerald-700 text-sm font-medium"
                  >
                    已熟练掌握
                  </button>
                </div>
              </div>
            ) : (
              <p className="text-slate-500 text-sm">
                今日 {DAILY_NEW} 个新词已全部学习完毕，去"测验"复习吧。
              </p>
            )}
          </div>
        )}

        {/* ============ 测验标签 ============ */}
        {tab === "quiz" && (
          <div className="bg-white rounded-xl border border-slate-200 p-5">
            {!quizQueue ? (
              <div>
                <p className="text-sm text-slate-600 mb-3">
                  当前到期待复习词汇：<span className="font-bold text-indigo-600">{dueWords.length}</span> 个
                </p>
                <button
                  onClick={startQuiz}
                  disabled={dueWords.length === 0}
                  className="px-4 py-2 rounded-lg bg-indigo-600 text-white text-sm font-medium disabled:opacity-40"
                >
                  开始测验
                </button>
                {dueWords.length === 0 && (
                  <p className="text-xs text-slate-400 mt-2">暂无到期复习词汇</p>
                )}
              </div>
            ) : quizMode ? (
              <div>
                <p className="text-xs text-slate-400 mb-3">
                  第 {quizIndex + 1} / {quizQueue.length} 题
                </p>
                {(() => {
                  const item = quizQueue[quizIndex];
                  return (
                    <div>
                      {quizMode === "recognition" ? (
                        <>
                          <div className="text-2xl font-bold mb-1 text-center">{quizWord(item.word)}</div>
                          {item.pos && (
                            <div className="text-center mb-3">
                              <span className="text-xs font-medium text-indigo-600 bg-indigo-50 border border-indigo-200 rounded px-1.5 py-0.5">
                                {item.pos}
                              </span>
                            </div>
                          )}
                          <div className="grid grid-cols-1 gap-2 mb-4">
                            {quizOptions.map((opt, i) => {
                              let style = "bg-slate-50 border-slate-200 hover:bg-slate-100";
                              if (quizAnswered) {
                                if (opt === item.meaning) style = "bg-emerald-50 border-emerald-400 text-emerald-700";
                                else style = "bg-slate-50 border-slate-200 opacity-50";
                              }
                              return (
                                <button
                                  key={i}
                                  onClick={() => submitQuizAnswer(opt)}
                                  disabled={quizAnswered}
                                  className={`border rounded-lg py-2 text-sm text-left px-3 ${style}`}
                                >
                                  {opt}
                                </button>
                              );
                            })}
                          </div>
                        </>
                      ) : (
                        <>
                          <div className="text-xl font-bold mb-1 text-center">{item.meaning}</div>
                          {item.pos && (
                            <div className="text-center mb-3">
                              <span className="text-xs font-medium text-indigo-600 bg-indigo-50 border border-indigo-200 rounded px-1.5 py-0.5">
                                {item.pos}
                              </span>
                            </div>
                          )}
                          <input
                            value={quizInput}
                            onChange={(e) => setQuizInput(e.target.value)}
                            disabled={quizAnswered}
                            placeholder="请输入韩语"
                            className="w-full border border-slate-200 rounded-lg px-3 py-2 mb-3 text-sm"
                          />
                          {!quizAnswered && (
                            <button
                              onClick={() => submitQuizAnswer(null)}
                              className="w-full py-2 rounded-lg bg-indigo-600 text-white text-sm font-medium mb-2"
                            >
                              提交
                            </button>
                          )}
                          {quizAnswered && (
                            <p className={`text-sm mb-2 ${quizCorrect ? "text-emerald-600" : "text-rose-500"}`}>
                              {quizCorrect ? "回答正确" : `回答错误，正确答案：${quizWord(item.word)}`}
                            </p>
                          )}
                        </>
                      )}

                      {!quizAnswered && (
                        <label className="flex items-center gap-2 text-xs text-slate-500 mb-3 select-none">
                          <input
                            type="checkbox"
                            checked={quizGuessed}
                            onChange={(e) => setQuizGuessed(e.target.checked)}
                          />
                          我是猜的
                        </label>
                      )}

                      {quizAnswered && (
                        <button
                          onClick={nextQuizItem}
                          className="w-full py-2 rounded-lg bg-indigo-600 text-white text-sm font-medium"
                        >
                          下一题
                        </button>
                      )}
                    </div>
                  );
                })()}
              </div>
            ) : (
              <div>
                <p className="text-sm font-bold mb-3">本轮测验结果</p>
                <div className="grid grid-cols-3 gap-2 text-center mb-4">
                  <div className="bg-emerald-50 rounded-lg p-3">
                    <div className="text-xl font-bold text-emerald-600">{quizStats.real}</div>
                    <div className="text-xs text-slate-500">真的会</div>
                  </div>
                  <div className="bg-amber-50 rounded-lg p-3">
                    <div className="text-xl font-bold text-amber-600">{quizStats.guessed}</div>
                    <div className="text-xs text-slate-500">猜对的</div>
                  </div>
                  <div className="bg-rose-50 rounded-lg p-3">
                    <div className="text-xl font-bold text-rose-500">{quizStats.wrong}</div>
                    <div className="text-xs text-slate-500">答错的</div>
                  </div>
                </div>
                <button
                  onClick={() => setQuizQueue(null)}
                  className="w-full py-2 rounded-lg bg-slate-100 text-sm font-medium"
                >
                  返回
                </button>
              </div>
            )}
          </div>
        )}

        {/* ============ 进度标签 ============ */}
        {tab === "progress" && (
          <div className="space-y-4">
            <div className="bg-white rounded-xl border border-slate-200 p-5">
              <p className="text-sm font-bold mb-3">词库总览</p>
              <div className="grid grid-cols-4 gap-2 text-center">
                <div className="bg-slate-50 rounded-lg p-2">
                  <div className="text-lg font-bold">{VOCAB.length}</div>
                  <div className="text-xs text-slate-400">总词数</div>
                </div>
                <div className="bg-slate-50 rounded-lg p-2">
                  <div className="text-lg font-bold">{stats.untouched}</div>
                  <div className="text-xs text-slate-400">未学习</div>
                </div>
                <div className="bg-amber-50 rounded-lg p-2">
                  <div className="text-lg font-bold text-amber-600">{stats.learning}</div>
                  <div className="text-xs text-slate-400">复习中</div>
                </div>
                <div className="bg-emerald-50 rounded-lg p-2">
                  <div className="text-lg font-bold text-emerald-600">{stats.mastered}</div>
                  <div className="text-xs text-slate-400">已掌握</div>
                </div>
              </div>
              <div className="mt-3 text-sm text-slate-600">
                今日到期复习：<span className="font-bold text-indigo-600">{dueWords.length}</span> 个
              </div>
              <div className="mt-4 border-t border-slate-100 pt-4">
                <p className="text-xs text-slate-400 mb-2">
                  进度已自动保存在本设备浏览器中，换设备或清除浏览器数据前可在此备份/恢复：
                </p>
              </div>
              <div className="flex gap-2 mt-2">
                <button
                  onClick={showExport}
                  className="flex-1 py-2 rounded-lg bg-indigo-600 text-white text-sm font-medium"
                >
                  显示导出文本
                </button>
              </div>
              {exportText && (
                <div className="mt-3">
                  <p className="text-xs text-slate-400 mb-1">全选下方文本并复制，保存到你自己的笔记里：</p>
                  <textarea
                    readOnly
                    value={exportText}
                    onFocus={(e) => e.target.select()}
                    className="w-full h-24 text-xs border border-slate-200 rounded-lg p-2 font-mono"
                  />
                </div>
              )}
              <div className="mt-4 border-t border-slate-100 pt-4">
                <p className="text-xs text-slate-400 mb-1">导入：粘贴之前备份的进度文本，点击应用（会覆盖当前进度）：</p>
                <textarea
                  value={importText}
                  onChange={(e) => setImportText(e.target.value)}
                  placeholder="粘贴进度JSON文本"
                  className="w-full h-24 text-xs border border-slate-200 rounded-lg p-2 font-mono mb-2"
                />
                <button
                  onClick={applyImport}
                  className="w-full py-2 rounded-lg bg-slate-100 text-sm font-medium"
                >
                  应用导入
                </button>
                {importMsg && <p className="text-xs text-emerald-600 mt-1">{importMsg}</p>}
              </div>
              <div className="mt-4 border-t border-slate-100 pt-4">
                <button
                  onClick={resetAll}
                  className="w-full py-2 rounded-lg bg-red-50 text-red-600 text-sm font-medium"
                >
                  重置全部进度
                </button>
              </div>
            </div>

            <div className="bg-white rounded-xl border border-slate-200 p-5">
              <p className="text-sm font-bold mb-3">四阶段备考计划</p>
              <div className="space-y-2">
                {STAGE_PLAN.map((s, i) => (
                  <div key={i} className="border border-slate-100 rounded-lg p-3">
                    <div className="flex justify-between items-baseline mb-1">
                      <span className="font-medium text-sm">{s.name}</span>
                      <span className="text-xs text-slate-400">{s.range}</span>
                    </div>
                    <p className="text-xs text-slate-500">{s.desc}</p>
                  </div>
                ))}
              </div>
            </div>
          </div>
        )}
      </div>
    </div>
  );
}
